PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE packages (     id           INTEGER PRIMARY KEY AUTOINCREMENT,     name         TEXT NOT NULL UNIQUE,     version      TEXT NOT NULL,     description  TEXT,     category     TEXT,     author       TEXT,     license      TEXT,     layer        TEXT DEFAULT 'both',     created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,     updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE files (     id           INTEGER PRIMARY KEY AUTOINCREMENT,     package_id   INTEGER NOT NULL REFERENCES packages(id) ON DELETE CASCADE,     filename     TEXT NOT NULL,     filepath     TEXT NOT NULL,     filetype     TEXT,     checksum     TEXT,     size_bytes   INTEGER,     content      BLOB,     layer        TEXT DEFAULT 'both' );
CREATE TABLE dependencies (     id               INTEGER PRIMARY KEY AUTOINCREMENT,     package_id       INTEGER NOT NULL REFERENCES packages(id) ON DELETE CASCADE,     depends_on_name  TEXT NOT NULL,     min_version      TEXT,     max_version      TEXT,     layer            TEXT DEFAULT 'both' );
CREATE TABLE installed (     id            INTEGER PRIMARY KEY AUTOINCREMENT,     package_id    INTEGER NOT NULL REFERENCES packages(id),     installed_at  DATETIME DEFAULT CURRENT_TIMESTAMP,     install_path  TEXT NOT NULL,     installed_by  TEXT,     layer         TEXT );
CREATE TABLE history (     id          INTEGER PRIMARY KEY AUTOINCREMENT,     action      TEXT NOT NULL,     package_id  INTEGER REFERENCES packages(id),     target_dir  TEXT,     timestamp   DATETIME DEFAULT CURRENT_TIMESTAMP,     status      TEXT,     layer       TEXT,     notes       TEXT );
CREATE TABLE toc (     id          INTEGER PRIMARY KEY AUTOINCREMENT,     title       TEXT NOT NULL,     parent_id   INTEGER REFERENCES toc(id),     position    INTEGER,     description TEXT,     layer       TEXT DEFAULT 'both' );
CREATE TABLE toc_entries (     id          INTEGER PRIMARY KEY AUTOINCREMENT,     toc_id      INTEGER NOT NULL REFERENCES toc(id) ON DELETE CASCADE,     package_id  INTEGER NOT NULL REFERENCES packages(id) ON DELETE CASCADE,     position    INTEGER );
CREATE TABLE glossary (     id                 INTEGER PRIMARY KEY AUTOINCREMENT,     term               TEXT NOT NULL UNIQUE,     definition         TEXT NOT NULL,     example            TEXT,     related_package_id INTEGER REFERENCES packages(id),     category           TEXT,     layer              TEXT DEFAULT 'both' );
CREATE TABLE aliases (     id          INTEGER PRIMARY KEY AUTOINCREMENT,     alias       TEXT NOT NULL UNIQUE,     target_type TEXT NOT NULL,     target_id   INTEGER,     target_name TEXT,     layer       TEXT DEFAULT 'both',     created_at  DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE kernel_slots (     id         INTEGER PRIMARY KEY AUTOINCREMENT,     slot       INTEGER UNIQUE NOT NULL,     kernel_id  INTEGER REFERENCES packages(id),     status     TEXT,     kernel_type TEXT,     loaded_at  DATETIME,     checksum   TEXT,     layer      TEXT DEFAULT 'both',     notes      TEXT );
INSERT INTO "kernel_slots" ("id","slot","kernel_id","status","kernel_type","loaded_at","checksum","layer","notes") VALUES(1,0,NULL,'empty','c_pure',NULL,NULL,'both','Pure C - maximum speed, peak traffic');
