INSERT INTO "kernel_slots" ("id","slot","kernel_id","status","kernel_type","loaded_at","checksum","layer","notes") VALUES(3,2,NULL,'empty','python_user',NULL,NULL,'both','Python userspace - flexible, moderate load');
INSERT INTO "kernel_slots" ("id","slot","kernel_id","status","kernel_type","loaded_at","checksum","layer","notes") VALUES(4,3,NULL,'empty','python_full',NULL,NULL,'both','Python 100 - full flexibility, dev/low priority');
CREATE TABLE sideloads (     id          INTEGER PRIMARY KEY AUTOINCREMENT,     slot        INTEGER NOT NULL REFERENCES kernel_slots(slot),     package_id  INTEGER NOT NULL REFERENCES packages(id),     priority    INTEGER,     status      TEXT,     layer       TEXT DEFAULT 'both' );
CREATE TABLE rotation_log (     id            INTEGER PRIMARY KEY AUTOINCREMENT,     from_slot     INTEGER,     to_slot       INTEGER,     trigger       TEXT,     traffic_load  REAL,     layer         TEXT,     timestamp     DATETIME DEFAULT CURRENT_TIMESTAMP,     success       INTEGER );
CREATE TABLE subscribers (     id              INTEGER PRIMARY KEY AUTOINCREMENT,     name            TEXT NOT NULL,     service         TEXT NOT NULL,     tunnel_in       TEXT,     tunnel_out      TEXT,     status          TEXT,     provisioned_at  DATETIME,     last_fed        DATETIME,     layer           TEXT DEFAULT 'both' );
CREATE TABLE feed_log (     id            INTEGER PRIMARY KEY AUTOINCREMENT,     subscriber_id INTEGER NOT NULL REFERENCES subscribers(id),     package_id    INTEGER REFERENCES packages(id),     action        TEXT,     status        TEXT,     bytes_moved   INTEGER,     timestamp     DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE layer_assignments (     id           INTEGER PRIMARY KEY AUTOINCREMENT,     service      TEXT NOT NULL,     layer        TEXT NOT NULL,     native_call  TEXT,     can_migrate  INTEGER DEFAULT 1,     reason       TEXT );
CREATE TABLE system_telemetry (     id            INTEGER PRIMARY KEY AUTOINCREMENT,     metric        TEXT NOT NULL,     value         REAL NOT NULL,     layer         TEXT,     slot          INTEGER,     subscriber_id INTEGER REFERENCES subscribers(id),     timestamp     DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE system_snapshots (     id          INTEGER PRIMARY KEY AUTOINCREMENT,     label       TEXT NOT NULL,     layer       TEXT,     state       TEXT,     checksum    TEXT,     is_good     INTEGER DEFAULT 1,     created_at  DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE entry_points (     id          INTEGER PRIMARY KEY AUTOINCREMENT,     name        TEXT UNIQUE NOT NULL,     status      TEXT DEFAULT 'reserved',     module      TEXT,     layer       TEXT DEFAULT 'both',     config      TEXT,     notes       TEXT );
