CREATE INDEX idx_packages_name      ON packages(name);
CREATE INDEX idx_packages_category  ON packages(category);
CREATE INDEX idx_packages_layer     ON packages(layer);
CREATE INDEX idx_files_package      ON files(package_id);
CREATE INDEX idx_files_filename     ON files(filename);
CREATE INDEX idx_files_layer        ON files(layer);
CREATE INDEX idx_deps_package       ON dependencies(package_id);
CREATE INDEX idx_deps_name          ON dependencies(depends_on_name);
CREATE INDEX idx_toc_parent         ON toc(parent_id);
CREATE INDEX idx_toc_position       ON toc(position);
CREATE INDEX idx_toc_entries_toc    ON toc_entries(toc_id);
CREATE INDEX idx_toc_entries_pkg    ON toc_entries(package_id);
CREATE INDEX idx_glossary_term      ON glossary(term);
CREATE INDEX idx_glossary_category  ON glossary(category);
CREATE INDEX idx_aliases_alias      ON aliases(alias);
CREATE INDEX idx_aliases_type       ON aliases(target_type);
CREATE INDEX idx_kernel_status      ON kernel_slots(status);
CREATE INDEX idx_kernel_slot        ON kernel_slots(slot);
CREATE INDEX idx_sideloads_slot     ON sideloads(slot);
CREATE INDEX idx_telemetry_time     ON system_telemetry(timestamp);
CREATE INDEX idx_telemetry_metric   ON system_telemetry(metric);
CREATE INDEX idx_telemetry_layer    ON system_telemetry(layer);
CREATE INDEX idx_subscribers_status ON subscribers(status);
CREATE INDEX idx_subscribers_service ON subscribers(service);
CREATE INDEX idx_feed_subscriber    ON feed_log(subscriber_id);
CREATE INDEX idx_feed_time          ON feed_log(timestamp);
CREATE INDEX idx_snapshots_good     ON system_snapshots(is_good);
CREATE INDEX idx_snapshots_layer    ON system_snapshots(layer);
CREATE INDEX idx_history_action     ON history(action);
CREATE INDEX idx_history_time       ON history(timestamp);
CREATE INDEX idx_rotation_time      ON rotation_log(timestamp);
CREATE VIEW view_toc_tree AS SELECT     t1.id       AS chapter_id,     t1.title    AS chapter,     t2.id       AS section_id,     t2.title    AS section,     t1.position AS chapter_order,     t2.position AS section_order FROM toc t1 LEFT JOIN toc t2 ON t2.parent_id = t1.id WHERE t1.parent_id IS NULL ORDER BY t1.position, t2.position;
CREATE VIEW view_active_kernel AS SELECT     ks.slot,     ks.kernel_type,     p.name      AS kernel_name,     p.version,     ks.loaded_at,     ks.layer FROM kernel_slots ks LEFT JOIN packages p ON ks.kernel_id = p.id WHERE ks.status = 'active';
CREATE VIEW view_subscriber_health AS SELECT     s.name,     s.service,     s.status,     s.last_fed,     ROUND((JULIANDAY('now') - JULIANDAY(s.last_fed)) * 24, 2) AS hours_since_fed FROM subscribers s ORDER BY hours_since_fed DESC;
CREATE VIEW view_installed AS SELECT     p.name,     p.version,     p.category,     i.install_path,     i.layer,     i.installed_at FROM installed i JOIN packages p ON i.package_id = p.id ORDER BY i.installed_at DESC;
